    long long n = points.size();
    if (n < 4) return 0;

    // Group points by their y-coordinate
    unordered_map<long long, vector<long long>> y_to_x;
    for (auto& p : points) {
        y_to_x[p[1]].push_back(p[0]);
    }

    long long result = 0;

    // For each y-coordinate, process the x-values
    for (auto& [y, xs] : y_to_x) {
        // Sort x-values for easier processing
        sort(xs.begin(), xs.end());

        // Count the number of points at this y-coordinate
        int count = xs.size();
        if (count < 2) continue;

        // For each pair of points at the same y-coordinate, consider them as a horizontal line
        // We can form a trapezoid by combining with two other horizontal lines
        // So we calculate combinations of 2 points from this line and multiply by combinations of 2 points from other lines
        // But we need to avoid overcounting

        // First, count the number of horizontal lines (same y-coordinate)
        // For each horizontal line, count the number of pairs of points
        // Then, for each pair of horizontal lines, count the number of pairs of points in each line
        // Multiply and add to the result

        // Use a map to store the number of pairs for each horizontal line
        unordered_map<long long, long long> line_pairs;
        for (int i = 0; i < count; ++i) {
            for (int j = i + 1; j < count; ++j) {
                line_pairs[xs[i]] += 1;
                line_pairs[xs[j]] += 1;
            }
        }

