            if (y1 == y) continue;

            // For each pair of points in this line
            for (int i = 0; i < xs1.size(); ++i) {
                for (int j = i + 1; j < xs1.size(); ++j) {
                    long long x1 = xs1[i];
                    long long x2 = xs1[j];
                    // Check if this pair has been used before
                    if (used_pairs.find({min(x1, x2), max(x1, x2)}) != used_pairs.end()) continue;

                    // Calculate the number of pairs in the current line and the other line
                    long long pairs_current = line_pairs[x1] + line_pairs[x2];
